use wasm_bindgen::prelude::*;

/// JS helper generated by build.rs (WGSL embedded, TypeScript stripped).
const JS_HELPER: &str = include_str!(concat!(env!("OUT_DIR"), "/helper.min.js"));

/// Bind to `globalThis.eval` so JS code runs in the global scope.
#[wasm_bindgen(js_namespace = global)]
extern "C" {
    #[wasm_bindgen(js_name = "eval")]
    fn js_eval_global(code: &str) -> JsValue;
}

/// Evaluate a JavaScript string in the global scope.
fn js_eval(code: &str) -> Result<JsValue, String> {
    let result = js_eval_global(&format!("({})", code));
    Ok(result)
}

/// Read `navigator.gpu` via a getter function defined by the test polyfill.
///
/// js_sys::global() caches the global object at WASM load time, before the
/// WebGPU polyfill runs. The polyfill defines __wt_get_gpu on globalThis
/// via Object.defineProperty. Calling this getter reads globalThis.navigator.gpu
/// at call time, bypassing the stale cached reference.
fn get_gpu() -> Result<JsValue, String> {
    let global_obj = js_sys::global();
    let getter = js_sys::Reflect::get(&global_obj, &JsValue::from_str("__wt_get_gpu"))
        .map_err(|e| format!("Failed to get __wt_get_gpu getter: {:?}", e))?;
    if getter.is_undefined() || getter.is_null() {
        return Err("__wt_get_gpu not defined (polyfill may not have run)".to_string());
    }
    let getter_fn = getter.dyn_ref::<js_sys::Function>()
        .ok_or("__wt_get_gpu is not a function")?;
    let result = getter_fn.call0(&global_obj)
        .map_err(|e| format!("__wt_get_gpu call failed: {:?}", e))?;
    if result.is_undefined() || result.is_null() {
        Err("navigator.gpu is not set (WebGPU polyfill may not be active)".to_string())
    } else {
        Ok(result)
    }
}

/// Call the WebGPU extract function. Returns a `Vec<u8>` of RGB values.
pub async fn extract_palette_webgpu(
    pixels: &[u8],
    width: u32,
    height: u32,
    color_count: u8,
    quality: u8,
) -> Result<Vec<u8>, String> {
    let expected_size = (width * height * 4) as usize;
    if pixels.len() < expected_size {
        return Err(format!(
            "Buffer too small: expected {} bytes for {}x{} RGBA image, got {}",
            expected_size, width, height, pixels.len()
        ));
    }

    // Read GPU via getter function (bypasses js_sys cached global)
    let gpu = get_gpu()
        .map_err(|e| format!("WebGPU setup error: {}", e))?;

    let extract_fn = js_eval(JS_HELPER)?;

    // Build input object
    let input = js_sys::Object::new();
    let pixels_arr = js_sys::Uint8Array::from(pixels);
    js_sys::Reflect::set(&input, &JsValue::from_str("pixels"), &pixels_arr.into()).ok();
    js_sys::Reflect::set(
        &input,
        &JsValue::from_str("w"),
        &JsValue::from_f64(width as f64),
    )
    .ok();
    js_sys::Reflect::set(
        &input,
        &JsValue::from_str("h"),
        &JsValue::from_f64(height as f64),
    )
    .ok();
    js_sys::Reflect::set(
        &input,
        &JsValue::from_str("maxC"),
        &JsValue::from_f64(color_count as f64),
    )
    .ok();
    js_sys::Reflect::set(
        &input,
        &JsValue::from_str("quality"),
        &JsValue::from_f64(quality as f64),
    )
    .ok();

    // Call the JS helper with gpu as first argument, input as second
    let call_args = js_sys::Array::new();
    call_args.push(&gpu);
    call_args.push(&input.into());
    let fn_ref = extract_fn.unchecked_ref::<js_sys::Function>();
    let promise_val = js_sys::Reflect::apply(fn_ref, &JsValue::UNDEFINED, &call_args)
        .map_err(|e| format!("WebGPU call failed: {:?}", e))?;

    // Convert JsValue to Promise for JsFuture
    let promise = js_sys::Promise::from(promise_val);
    let result = wasm_bindgen_futures::JsFuture::from(promise)
        .await
        .map_err(|e| format!("WebGPU promise rejected: {:?}", e))?;

    let uint8 = js_sys::Uint8Array::from(result);
    let mut out = vec![0u8; uint8.length() as usize];
    uint8.copy_to(&mut out);
    Ok(out)
}

